using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata: GetTypeInfo<T>() returns JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Type info for Person: {personInfo.Type.Name}, kind: {personInfo.Kind}");

// 2) Probe without throwing: TryGetTypeInfo returns false instead of throwing.
//    Works for types the resolver *can* handle...
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"TryGet Person  -> found ({found!.Type.Name})");
else
    Console.WriteLine("TryGet Person  -> not found");

//    ...and for types that aren't available (e.g. a resolver that only
//    knows about a fixed set of types).
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine()   // empty — resolves nothing
};

if (limited.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("TryGet Person (limited) -> found");
else
    Console.WriteLine("TryGet Person (limited) -> not found  (no throw!)");

record Person(string Name, int Age);

